     /*  History:                                                           */
     /*                                                                     */
     /*  Datum       Name          Änderung                                 */
     /*  ----------  ------------  ---------------------------------------  */
     /*                                                                     */
     /* =================================================================== */
     /*   >>PRE-COMPILER<<                                                  */
     /*     >>CRTCMD<<    CRTBNDCL  PGM(QTEMP/&OB) +                        */
     /*                             SRCFILE(&SL/&SF) SRCMBR(&SM);           */
     /*     >>IMPORTANT<<                                                   */
     /*       >>PARM<<    OPTION(*EVENTF);                                  */
     /*     >>END-IMPORTANT<<                                               */
     /*     >>EXECUTE<<                                                     */
     /*     >>CMD<<       CALL   PGM(QTEMP/A_INSTALL) +                     */
     /*                          PARM('*CURRENT' '&SF' '&LI' 'GER' 'L_NO'); */
     /*     >>CMD<<       DLTPGM PGM(QTEMP/A_INSTALL);                      */
     /*   >>END-PRE-COMPILER<<                                              */
     /* =================================================================== */
             PGM        PARM(&TGTRLS &SRCFILE &TOLIB  &LNG &USELIBL)

             DCL        VAR(&TGTRLS   ) TYPE(*CHAR) LEN(10)
             DCL        VAR(&SRCFILE  ) TYPE(*CHAR) LEN(10)
             DCL        VAR(&TOLIB    ) TYPE(*CHAR) LEN(10)
             DCL        VAR(&LNG      ) TYPE(*CHAR) LEN( 3)
             DCL        VAR(&USELIBL  ) TYPE(*CHAR) LEN(10)

             DCL        VAR(&SRCLIB   ) TYPE(*CHAR) LEN(10)

             DCL        VAR(&CRTMSGF  ) TYPE(*CHAR) LEN(10)
             DCL        VAR(&MSGF     ) TYPE(*CHAR) LEN(10) VALUE('IFS')

             DCL        VAR(&BNDLIBL  ) TYPE(*CHAR) LEN(10) VALUE('*LIBL')

             CHGVAR     VAR(&SRCLIB) VALUE(&TOLIB   )

     /* -------------------------------- */
     /*  Delete old objects              */
     /* -------------------------------- */
             DLTMOD     MODULE(&TOLIB/IFSR01)
             MONMSG     MSGID(CPF2105)

             DLTMOD     MODULE(&TOLIB/IFSTEST_01)
             MONMSG     MSGID(CPF2105)

             DLTMOD     MODULE(&TOLIB/IFSTEST_02)
             MONMSG     MSGID(CPF2105)

             DLTMOD     MODULE(&TOLIB/IFSTEST_03)
             MONMSG     MSGID(CPF2105)

             DLTMOD     MODULE(&TOLIB/IFSTEST_04)
             MONMSG     MSGID(CPF2105)

             DLTMOD     MODULE(&TOLIB/IFSTEST_05)
             MONMSG     MSGID(CPF2105)

             DLTMOD     MODULE(&TOLIB/IFSTEST_06)
             MONMSG     MSGID(CPF2105)

             DLTMOD     MODULE(&TOLIB/IFSTEST_07)
             MONMSG     MSGID(CPF2105)

             DLTMOD     MODULE(&TOLIB/IFSTEST_08)
             MONMSG     MSGID(CPF2105)

             DLTMOD     MODULE(&TOLIB/IFSTEST_09)
             MONMSG     MSGID(CPF2105)

             DLTMOD     MODULE(&TOLIB/IFSTEST_10)
             MONMSG     MSGID(CPF2105)

             DLTMOD     MODULE(&TOLIB/IFSTEST_30)
             MONMSG     MSGID(CPF2105)

             DLTMOD     MODULE(&TOLIB/IFSTEST_31)
             MONMSG     MSGID(CPF2105)

             DLTMOD     MODULE(&TOLIB/IFSTEST_32)
             MONMSG     MSGID(CPF2105)

             DLTMOD     MODULE(&TOLIB/IFSTEST_33)
             MONMSG     MSGID(CPF2105)

             DLTMOD     MODULE(&TOLIB/IFSTEST_98)
             MONMSG     MSGID(CPF2105)

             DLTMOD     MODULE(&TOLIB/IFSTEST_99)
             MONMSG     MSGID(CPF2105)

             DLTSRVPGM  SRVPGM(&TOLIB/IFS)
             MONMSG     MSGID(CPF2105)

             DLTPGM     PGM(&TOLIB/IFSTEST_01)
             MONMSG     MSGID(CPF2105)

             DLTPGM     PGM(&TOLIB/IFSTEST_02)
             MONMSG     MSGID(CPF2105)

             DLTPGM     PGM(&TOLIB/IFSTEST_03)
             MONMSG     MSGID(CPF2105)

             DLTPGM     PGM(&TOLIB/IFSTEST_04)
             MONMSG     MSGID(CPF2105)

             DLTPGM     PGM(&TOLIB/IFSTEST_05)
             MONMSG     MSGID(CPF2105)

             DLTPGM     PGM(&TOLIB/IFSTEST_06)
             MONMSG     MSGID(CPF2105)

             DLTPGM     PGM(&TOLIB/IFSTEST_07)
             MONMSG     MSGID(CPF2105)

             DLTPGM     PGM(&TOLIB/IFSTEST_08)
             MONMSG     MSGID(CPF2105)

             DLTPGM     PGM(&TOLIB/IFSTEST_09)
             MONMSG     MSGID(CPF2105)

             DLTPGM     PGM(&TOLIB/IFSTEST_10)
             MONMSG     MSGID(CPF2105)

             DLTPGM     PGM(&TOLIB/IFSTEST_30)
             MONMSG     MSGID(CPF2105)

             DLTPGM     PGM(&TOLIB/IFSTEST_31)
             MONMSG     MSGID(CPF2105)

             DLTPGM     PGM(&TOLIB/IFSTEST_32)
             MONMSG     MSGID(CPF2105)

             DLTPGM     PGM(&TOLIB/IFSTEST_33)
             MONMSG     MSGID(CPF2105)

             DLTPGM     PGM(&TOLIB/IFSTEST_98)
             MONMSG     MSGID(CPF2105)

             DLTPGM     PGM(&TOLIB/IFSTEST_99)
             MONMSG     MSGID(CPF2105)

             DLTMSGF    MSGF(&TOLIB/&MSGF)
             MONMSG     MSGID(CPF2105)

             RMVMSG     PGMQ(*SAME (*)) CLEAR(*ALL)

     /* -------------------------------- */
     /*  Create message file             */
     /* -------------------------------- */
             IF         COND(&LNG *EQ 'ENG') THEN(DO)
                CHGVAR     VAR(&CRTMSGF) VALUE('A_MSG_ENG')
             ENDDO
             ELSE       CMD(DO)
                CHGVAR     VAR(&CRTMSGF) VALUE('A_MSG_GER')
             ENDDO

             CRTMSGF    MSGF(&TOLIB/&MSGF) +
                          TEXT('Export Journal Entries')

             CRTCLPGM   PGM(QTEMP/&CRTMSGF) +
                          SRCFILE(&SRCLIB/&SRCFILE) SRCMBR(*PGM) +
                          OPTION(*LSTDBG) +
                          TGTRLS(&TGTRLS)
             DLTSPLF    FILE(&CRTMSGF  ) JOB(*) SPLNBR(*LAST)
             MONMSG     MSGID(CPF0000)

             CALL       PGM(QTEMP/&CRTMSGF) PARM(&TOLIB)
             DLTPGM     PGM(QTEMP/&CRTMSGF)

     /* -------------------------------- */
     /*  Use *LIBL at runtime?           */
     /* -------------------------------- */
             IF         COND(&USELIBL *NE 'L_NO') THEN(DO)
                CHGVAR     VAR(&BNDLIBL) VALUE(&TOLIB)
             ENDDO

     /* -------------------------------- */
     /*  Create modules                  */
     /* -------------------------------- */
             CRTRPGMOD  MODULE(&TOLIB/IFSR01) +
                          SRCFILE(&SRCLIB/&SRCFILE) SRCMBR(*MODULE) +
                          DBGVIEW(*LIST) TRUNCNBR(*NO) +
                          TGTRLS(&TGTRLS)
             DLTSPLF    FILE(IFSR01  ) JOB(*) SPLNBR(*LAST)
             MONMSG     MSGID(CPF0000)

     /* -------------------------------- */
     /*  Create service programs         */
     /* -------------------------------- */
             CRTSRVPGM  SRVPGM(&TOLIB/IFS) +
                          MODULE(&TOLIB/IFSR01) +
                          EXPORT(*SRCFILE) +
                          SRCFILE(&SRCLIB/&SRCFILE) +
                          SRCMBR(IFS) +
                          ACTGRP(*CALLER) +
                          BNDDIR(QC2LE) +
                          BNDSRVPGM(&BNDLIBL/BASICS1) +
                          DETAIL(*BASIC) +
                          TEXT('IFS File API') +
                          TGTRLS(&TGTRLS)
             DLTSPLF    FILE(IFS) JOB(*) SPLNBR(*LAST)
             MONMSG     MSGID(CPF0000)

     /* -------------------------------- */
     /*  Create test programs            */
     /* -------------------------------- */

     /* -------------------------------- */
     /*  Delete obsolete objects         */
     /* -------------------------------- */
             DLTMOD     MODULE(&TOLIB/IFSR01)

             ENDPGM

     /*-----------------------------------------------------------------------*/
     /* STRPREPRC Compile Options:                                            */
     /* >>PRE-COMPILER<<                                                      */
     /*  >>CRTCMD<<   CRTBNDCL   PGM(QTEMP/&OB) +                             */
     /*                          SRCFILE(&SL/&SF) SRCMBR(&SM);                */
     /*   >>COMPILE<<                                                         */
     /*    >>PARM<<  TEXT('Tool: EXPJRNE    (Export Journal Entries  ) Eng'); */
     /*   >>END-COMPILE<<                                                     */
     /*   >>EXECUTE<<                                                         */
     /*   >>CMD<<     CALL PGM(QTEMP/&OB) PARM(&LI &OB);                      */
     /*   >>CMD<<     DLTPGM PGM(QTEMP/&OB);                                  */
     /* >>END-PRE-COMPILER<<                                                  */
     /*-----------------------------------------------------------------------*/
             PGM        PARM(&LI)

             DCL        VAR(&LI) TYPE(*CHAR) LEN(10)

     /* ----------------------------------------------------------- */
     /*   Cmd-ADDMSGD für Message-ID :   IFS1000                    */
     /* &1[1000] File '&2' has not been opend. Error code &3.       */
     /* ----------------------------------------------------------- */

             ADDMSGD +
                MSGID(IFS1000) +
                MSGF(&LI/IFS) +
                MSG(+
'&1[1000] File ''&2'' has not been opend. Error code &3.'             +
                ) +
                SECLVL(+
'&N &N Cause   . . . . :   The Unix open() function returned error cod-
e &3 when attemting to open file ''&2''. The error text is: ''&4''.'  +
                ) +
                SEV(00) +
                FMT( +
                    (*CHAR 001) +
                    (*CHAR 128) +
                    (*DEC 010 0) +
                    (*CHAR 128) +
                ) +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

     /* ----------------------------------------------------------- */
     /*   Cmd-ADDMSGD für Message-ID :   IFS1001                    */
     /* &1[1001] File '&2' has not been closed. Error code &3.      */
     /* ----------------------------------------------------------- */

             ADDMSGD +
                MSGID(IFS1001) +
                MSGF(&LI/IFS) +
                MSG(+
'&1[1001] File ''&2'' has not been closed. Error code &3.'            +
                ) +
                SECLVL(+
'&N &N Cause   . . . . :   The Unix close() function returned error co-
de &3 when attemting to close file ''&2''. The error text is: ''&4''.'+
                ) +
                SEV(00) +
                FMT( +
                    (*CHAR 001) +
                    (*CHAR 128) +
                    (*DEC 010 0) +
                    (*CHAR 128) +
                ) +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

     /* ----------------------------------------------------------- */
     /*   Cmd-ADDMSGD für Message-ID :   IFS1002                    */
     /* &1[1002] Data has not been written to file '&2'. Error code */
     /* ----------------------------------------------------------- */

             ADDMSGD +
                MSGID(IFS1002) +
                MSGF(&LI/IFS) +
                MSG(+
'&1[1002] Data has not been written to file ''&2''. Error code &3.'   +
                ) +
                SECLVL(+
'&N &N Cause   . . . . :   The Unix write() function returned error co-
de &3 when attemting to write to file ''&2''. The error text is: ''&4'-
'.'                                                                   +
                ) +
                SEV(00) +
                FMT( +
                    (*CHAR 001) +
                    (*CHAR 128) +
                    (*DEC 010 0) +
                    (*CHAR 128) +
                ) +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

     /* ----------------------------------------------------------- */
     /*   Cmd-ADDMSGD für Message-ID :   IFS1003                    */
     /* &1[1003] File '&2' has not been moved to '&3'. Error code & */
     /* ----------------------------------------------------------- */

             ADDMSGD +
                MSGID(IFS1003) +
                MSGF(&LI/IFS) +
                MSG(+
'&1[1003] File ''&2'' has not been moved to ''&3''. Error code &4.'   +
                ) +
                SECLVL(+
'&N &N Cause   . . . . :   The Unix Qp0lRenameKeep() function returned-
error code &4 when attemting to move file ''&2'' to ''&3''. The error -
text is: ''&5''.'                                                     +
                ) +
                SEV(00) +
                FMT( +
                    (*CHAR 001) +
                    (*CHAR 128) +
                    (*CHAR 128) +
                    (*DEC 010 0) +
                    (*CHAR 128) +
                ) +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

     /* ----------------------------------------------------------- */
     /*   Cmd-ADDMSGD für Message-ID :   IFS1004                    */
     /* &1[1004] Data has not been red from file '&2'. Error code & */
     /* ----------------------------------------------------------- */

             ADDMSGD +
                MSGID(IFS1004) +
                MSGF(&LI/IFS) +
                MSG(+
'&1[1004] Data has not been red from file ''&2''. Error code &3.'     +
                ) +
                SECLVL(+
'&N &N Cause   . . . . :   The Unix read() function returned error cod-
e &3 when attemting to read from file ''&2''. The error text is: ''&4'-
'.'                                                                   +
                ) +
                SEV(00) +
                FMT( +
                    (*CHAR 001) +
                    (*CHAR 128) +
                    (*DEC 010 0) +
                    (*CHAR 128) +
                ) +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

     /* ----------------------------------------------------------- */
     /*   Cmd-ADDMSGD für Message-ID :   IFS1005                    */
     /* &1[1005] File '&2' has not been deleted. Error code &3.     */
     /* ----------------------------------------------------------- */

             ADDMSGD +
                MSGID(IFS1005) +
                MSGF(&LI/IFS) +
                MSG(+
'&1[1005] File ''&2'' has not been deleted. Error code &3.'           +
                ) +
                SECLVL(+
'&N &N Cause   . . . . :   The Unix unlink() function returned error c-
ode &3 when attemting to delete file ''&2''. The error text is: ''&4''-
.'                                                                    +
                ) +
                SEV(00) +
                FMT( +
                    (*CHAR 001) +
                    (*CHAR 128) +
                    (*DEC 010 0) +
                    (*CHAR 128) +
                ) +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

     /* ----------------------------------------------------------- */
     /*   Cmd-ADDMSGD für Message-ID :   IFS1006                    */
     /* &1[1006] The size of file '&2' has not been retrieved. Erro */
     /* ----------------------------------------------------------- */

             ADDMSGD +
                MSGID(IFS1006) +
                MSGF(&LI/IFS) +
                MSG(+
'&1[1006] The size of file ''&2'' has not been retrieved. Error code &-
3.'                                                                   +
                ) +
                SECLVL(+
'&N &N Cause   . . . . :   The Unix stat() function returned error cod-
e &3 when attemting to retrieve the status of file ''&2''. The error t-
ext is: ''&4''.'                                                      +
                ) +
                SEV(00) +
                FMT( +
                    (*CHAR 001) +
                    (*CHAR 128) +
                    (*DEC 010 0) +
                    (*CHAR 128) +
                ) +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

     /* ----------------------------------------------------------- */
     /*   Cmd-ADDMSGD für Message-ID :   IFS1007                    */
     /* &1[1007] The size of file '&2' has not been changed. Error  */
     /* ----------------------------------------------------------- */

             ADDMSGD +
                MSGID(IFS1007) +
                MSGF(&LI/IFS) +
                MSG(+
'&1[1007] The size of file ''&2'' has not been changed. Error code &3.-
'                                                                     +
                ) +
                SECLVL(+
'&N &N Cause   . . . . :   The Unix ftruncate() function returned erro-
r code &3 when attemting change the size of file ''&2''. The error tex-
t is: ''&4''.'                                                        +
                ) +
                SEV(00) +
                FMT( +
                    (*CHAR 001) +
                    (*CHAR 128) +
                    (*DEC 010 0) +
                    (*CHAR 128) +
                ) +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

     /* ----------------------------------------------------------- */
     /*   Cmd-ADDMSGD für Message-ID :   IFS1008                    */
     /* &1[1008] The offset of the read/write pointer of file '&2'  */
     /* ----------------------------------------------------------- */

             ADDMSGD +
                MSGID(IFS1008) +
                MSGF(&LI/IFS) +
                MSG(+
'&1[1008] The offset of the read/write pointer of file ''&2'' has not -
been changed. Error code: &3.'                                        +
                ) +
                SECLVL(+
'&N &N Cause   . . . . :   The Unix lseek() function returned error co-
de &3 when attemting set the new file offset. The error text is: ''&4'-
'.'                                                                   +
                ) +
                SEV(00) +
                FMT( +
                    (*CHAR 001) +
                    (*CHAR 128) +
                    (*DEC 010 0) +
                    (*CHAR 128) +
                    (*DEC 010 0) +
                    (*DEC 010 0) +
                ) +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

     /* ----------------------------------------------------------- */
     /*   Cmd-ADDMSGD für Message-ID :   IFS1009                    */
     /* &1[1009] File '&2' has not been renamed to '&3'. Error code */
     /* ----------------------------------------------------------- */

             ADDMSGD +
                MSGID(IFS1009) +
                MSGF(&LI/IFS) +
                MSG(+
'&1[1009] File ''&2'' has not been renamed to ''&3''. Error code &4.' +
                ) +
                SECLVL(+
'&N &N Cause   . . . . :   The Unix Qp0lRenameKeep() function returned-
 error code &4 when attempting to rename file ''&2'' to ''&3''. The er-
ror text is: ''&5''.'                                                 +
                ) +
                SEV(00) +
                FMT( +
                    (*CHAR 001) +
                    (*CHAR 128) +
                    (*CHAR 128) +
                    (*DEC 010 0) +
                    (*CHAR 128) +
                ) +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

     /* ----------------------------------------------------------- */
     /*   Cmd-ADDMSGD für Message-ID :   IFS1011                    */
     /* &1[1011] Directory '&2' has not been found.                 */
     /* ----------------------------------------------------------- */

             ADDMSGD +
                MSGID(IFS1011) +
                MSGF(&LI/IFS) +
                MSG(+
'&1[1011] Directory ''&2'' has not been found.'                       +
                ) +
                SECLVL(+
'&N &N Cause   . . . . :   The requested function can not be performed-
 because directory ''&2'' does not exist.'                            +
                ) +
                SEV(00) +
                FMT( +
                    (*CHAR 001) +
                    (*CHAR 128) +
                ) +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

     /* ----------------------------------------------------------- */
     /*   Cmd-ADDMSGD für Message-ID :   IFS1012                    */
     /* &1[1012] File '&2' has not been found.                      */
     /* ----------------------------------------------------------- */

             ADDMSGD +
                MSGID(IFS1012) +
                MSGF(&LI/IFS) +
                MSG(+
'&1[1012] File ''&2'' has not been found.'                            +
                ) +
                SECLVL(+
'&N &N Cause   . . . . :   The requested function can not be performed-
 because file ''&2'' does not exist.'                                 +
                ) +
                SEV(00) +
                FMT( +
                    (*CHAR 001) +
                    (*CHAR 128) +
                ) +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

     /* ----------------------------------------------------------- */
     /*   Cmd-ADDMSGD für Message-ID :   IFS1013                    */
     /* &1[1013] File '&2' exists.                                  */
     /* ----------------------------------------------------------- */

             ADDMSGD +
                MSGID(IFS1013) +
                MSGF(&LI/IFS) +
                MSG(+
'&1[1013] File ''&2'' exists.'                                        +
                ) +
                SECLVL(+
'&N &N Cause   . . . . :   The requested function can not be performed-
 because file ''&2'' already exists.'                                 +
                ) +
                SEV(00) +
                FMT( +
                    (*CHAR 001) +
                    (*CHAR 128) +
                ) +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

     /* ----------------------------------------------------------- */
     /*   Cmd-ADDMSGD für Message-ID :   IFS1014                    */
     /* &1[1014] File name '&2' contains invalid characters.        */
     /* ----------------------------------------------------------- */

             ADDMSGD +
                MSGID(IFS1014) +
                MSGF(&LI/IFS) +
                MSG(+
'&1[1014] File name ''&2'' contains invalid characters.'              +
                ) +
                SECLVL(+
'&N &N Cause   . . . . :   The requested function can not be performed-
 because file name ''&2'' contains invalid characters.'               +
                ) +
                SEV(00) +
                FMT( +
                    (*CHAR 001) +
                    (*CHAR 128) +
                ) +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

     /* ----------------------------------------------------------- */
     /*   Cmd-ADDMSGD für Message-ID :   IFS1015                    */
     /* &1[1015] Directory '&2' exists.                             */
     /* ----------------------------------------------------------- */

             ADDMSGD +
                MSGID(IFS1015) +
                MSGF(&LI/IFS) +
                MSG(+
'&1[1015] Directory ''&2'' exists.'                                   +
                ) +
                SECLVL(+
'&N &N Cause   . . . . :   The requested function can not be performed-
 because directory ''&2'' already exists.'                            +
                ) +
                SEV(00) +
                FMT( +
                    (*CHAR 001) +
                    (*CHAR 128) +
                ) +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

     /* ----------------------------------------------------------- */
     /*   Cmd-ADDMSGD für Message-ID :   IFS1016                    */
     /* &1[1016] Buffer overflow occurred while reading from IFS fi */
     /* ----------------------------------------------------------- */

             ADDMSGD +
                MSGID(IFS1016) +
                MSGF(&LI/IFS) +
                MSG(+
'&1[1016] Buffer overflow occurred while reading from IFS file ''&2''.-
'                                                                     +
                ) +
                SECLVL(+
'&N &N Ursache . . . . :   A buffer overflow occured while attempting -
to read data from IFS file ''&2''. The specified buffer size of &3 byt-
es was too small to read a line completely.'                          +
                ) +
                SEV(00) +
                FMT( +
                    (*CHAR 001) +
                    (*CHAR 128) +
                    (*DEC 010 0) +
                ) +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

     /* ----------------------------------------------------------- */
     /*   Cmd-ADDMSGD für Message-ID :   IFS1017                    */
     /* &1[1017] Entry has not been red from directory '&2'.        */
     /* ----------------------------------------------------------- */

             ADDMSGD +
                MSGID(IFS1017) +
                MSGF(&LI/IFS) +
                MSG(+
'&1[1017] Entry has not been red from directory ''&2''.'              +
                ) +
                SECLVL(+
'&N &N Cause   . . . . :   The Unix readdir() function returned error -
code &3 when attempting to read the next entry from directory ''&2''. -
The error text is: ''&4''.'                                           +
                ) +
                SEV(00) +
                FMT( +
                    (*CHAR 001) +
                    (*CHAR 128) +
                    (*DEC 010 0) +
                    (*CHAR 128) +
                ) +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

     /* ----------------------------------------------------------- */
     /*   Cmd-ADDMSGD für Message-ID :   IFS1018                    */
     /* &1[1018] Attributes of file '&2' not retrieved.             */
     /* ----------------------------------------------------------- */

             ADDMSGD +
                MSGID(IFS1018) +
                MSGF(&LI/IFS) +
                MSG(+
'&1[1018] Attributes of file ''&2'' not retrieved.'                   +
                ) +
                SECLVL(+
'&N &N Cause   . . . . :   The Unix stat() function returned error cod-
e &3 when attempting to retrieve attributes of file ''&2''. The error -
text is: ''&4''.'                                                     +
                ) +
                SEV(00) +
                FMT( +
                    (*CHAR 001) +
                    (*CHAR 128) +
                    (*DEC 010 0) +
                    (*CHAR 128) +
                ) +
                ALROPT(*NO) +
                CCSID( 65535) +
                /*  -EOF-  */

     /* ----------------------------------------------------------- */
     /*   Cmd-ADDMSGD für Message-ID :   IFS1019                    */
     /* &1[1019] Directory '&2' not opened.                         */
     /* ----------------------------------------------------------- */

             ADDMSGD +
                MSGID(IFS1019) +
                MSGF(&LI/IFS) +
                MSG(+
'&1[1019] Directory ''&2'' not opened.'                               +
