/end-free * P f_getIfsCurDir... P E * *========================================================================= * Changes the current working directory. *========================================================================= * Parameters: * i_dir - Directory that should become the current directory. * o_msg - Error message. * * Returns: * rc - Returns 0 on success, else -1. *========================================================================= P f_chgIfsCurDir... P B export * D f_chgIfsCurDir... D PI 10I 0 D i_dir const like(ifs_path_t ) D o_msg like(msg_t ) D options(*nopass: *omit) * * Return value D rc S 10I 0 inz(RC_ERROR) * * Parameter positions D p_isMsg C const(2) * * Fields for optional parameters D msg DS likeds(msg_t ) inz * * Helper fields D tmpDir DS likeds(Qlg_Path_Name_t) inz * * Local fields D isPresent S 10I 0 inz * /COPY QIFS,IFS1030 * --------------------------------------------------------- /free
// Clear error message msg = lf_newIfsMsg(cMsg_ID_OK);
dou '1';
// Prepare path name tmpDir = lf_initializePath(i_dir);
// Change current working directory if (QlgChdir(tmpDir) <> 0); // ... create error message on error clear IFS1030; IFS10301 = i_dir; IFS10302 = f_errno; IFS10303 = f_strerror(f_errno); msg = lf_newIfsMsg('IFS1030': IFS1030); leave; endif;
rc = RC_OK; enddo;
// Set message type to *ESCAPE if it is not an OK message if (msg.ID <> cMsg_ID_OK); msg.type = cMsg_Escape; endif;
// If the message parameter was passed ... if (%parms >= p_isMsg); // then check if it was omitted CEETSTA(isPresent: p_isMsg: *omit); // If the parameter was not omitted ... if (isPresent = 1); // then pass back the message o_msg = msg; endif; else; // else send message if (msg.ID <> cMsg_ID_OK); f_sndPgmMsg(msg: cMsg_Prv); endif; endif;
return rc;
/end-free * P f_chgIfsCurDir... P E * *========================================================================= R * *** private *** * Removes the entries of a given directory. *========================================================================= P lf_removeDirectoryEntry... P B * D lf_removeDirectoryEntry... D PI N D i_level 10I 0 value D i_directory value like(ifs_path_t ) D i_entry value like(ifs_path_t ) D i_type value like(ifs_type_t ) D i_pUserData * value D o_msg value like(msg_t ) * * Local fields D tmpPath S like(ifs_path_t ) inz D tmpMsg DS likeds(msg_t ) inz * --------------------------------------------------------- /free
tmpPath = %trimR(i_directory) + i_entry;
select; when (i_type = cIFS_DIRENT_TYPE_DIRECTORY or i_type = cIFS_DIRENT_TYPE_FOLDER); if (f_dltIfsDir(tmpPath: *omit: tmpMsg) = cIFS_ERROR); o_msg = tmpMsg; return cFalse; endif;
when (i_type = cIFS_DIRENT_TYPE_FILE or i_type = cIFS_DIRENT_TYPE_DOCUMENT); if (f_deleteIfsFile(tmpPath: tmpMsg) = cIFS_ERROR); o_msg = tmpMsg; return cFalse; endif;
endsl;
o_msg = lf_newIfsMsg(cMsg_ID_OK);
return cTrue;
/end-free * P lf_removeDirectoryEntry... P E * *========================================================================= R * *** private *** * Removes the entries of a given directory (test mode). *========================================================================= P lf_removeDirectoryEntryTestMode... P B * D lf_removeDirectoryEntryTestMode... D PI N D i_level 10I 0 value D i_directory value like(ifs_path_t ) D i_entry value like(ifs_path_t ) D i_type value like(ifs_type_t ) D i_pUserData * value D o_msg value like(msg_t ) * * Local fields D options S 10I 0 based(i_pUserData) D tmpPath S like(ifs_path_t ) inz D tmpMsg DS likeds(msg_t ) inz * --------------------------------------------------------- /free
tmpPath = %trimR(i_directory) + i_entry;
select; when (i_type = cIFS_DIRENT_TYPE_DIRECTORY or i_type = cIFS_DIRENT_TYPE_FOLDER);
f_sndPgmMsg(f_newMsg(cMSG_ID_NONE : 'Test mode: Removed ' + %trim(tmpPath)) : cMsg_Same);
when (i_type = cIFS_DIRENT_TYPE_FILE or i_type = cIFS_DIRENT_TYPE_DOCUMENT);
f_sndPgmMsg(f_newMsg(cMSG_ID_NONE : 'Test mode: Removed ' + %trim(tmpPath)) : cMsg_Same);
endsl;
o_msg = lf_newIfsMsg(cMsg_ID_OK);
return cTrue;
/end-free * P lf_removeDirectoryEntryTestMode... P E * *========================================================================= R * *** private *** * Adds the file path to the local file handle table, because there is * no way to get the path back from the Unix file handle. *========================================================================= P lp_addEntryToFileHandleTable... P B * D lp_addEntryToFileHandleTable... D PI D i_hFile const like(ifs_hFile_t) D i_path const like(ifs_path_t ) D i_useTmpBuffer N const * * Local fields D i S 10I 0 inz * --------------------------------------------------------- /free
if g_numHandles < %elem(g_handleList.hFile); i = %lookup(0: g_handleList.hFile: 1: g_numHandles + 1); else; i = %lookup(0: g_handleList.hFile: 1: g_numHandles); endif;
p_assert(i > 0 : 'Maximum number of handles reached.' );
if i > 0; g_handleList.hFile(i) = i_hFile; g_handleList.useTmpBuffer(i) = i_useTmpBuffer; g_handleList.path(i) = i_path; if i > g_numHandles; p_assert(i = g_numHandles + 1); g_numHandles = g_numHandles + 1; endif; endif;
// Create temporay buffer used by f_writeLineIfsFile() if (i_useTmpBuffer and g_tempBuffer.pData = *NULL); g_tempBuffer.size = cBUFFER_SIZE; g_tempBuffer.pData = %alloc(g_tempBuffer.size); endif;
return;
/end-free * P lp_addEntryToFileHandleTable... P E * *========================================================================= R * *** private *** * Gets the path from the local file handle. *========================================================================= P lf_getPathFromFileHandleTable... P B * D lf_getPathFromFileHandleTable... D PI like(ifs_path_t) D i_hFile const like(ifs_hFile_t) * * Return value D path S like(ifs_path_t ) inz('*N') * * Localfields D i S 10I 0 inz * --------------------------------------------------------- /free
// Search for the file handle i = lf_getFileHandleTableIndex(i_hFile); if i > 0; // and get back the path path = g_handleList.path(i); endif;
return path;
/end-free * P lf_getPathFromFileHandleTable... P E * *========================================================================= R * *** private *** * Returns TRUE if f_writeLineIfsFile() must use a temporary * buffer, else FALSE *========================================================================= P lf_useTmpBuffer... P B * D lf_useTmpBuffer... D PI N D i_hFile const like(ifs_hFile_t) * * Return value D useTmpBuffer S N inz(cFalse) * * Localfields D i S 10I 0 inz * --------------------------------------------------------- /free
// Search for the file handle i = lf_getFileHandleTableIndex(i_hFile); if i > 0; useTmpBuffer = g_handleList.useTmpBuffer(i); endif;
return useTmpBuffer;
/end-free * P lf_useTmpBuffer... P E * *========================================================================= R * *** private *** * Checks and reallocates size of temporary write buffer. Returns * buffer pointer. *========================================================================= P lf_checkAndReallocateTmpBuffer... P B * D lf_checkAndReallocateTmpBuffer... D PI * D i_hFile const like(ifs_hFile_t) D i_newSize 10I 0 const * * Return value D pTmpBuffer S * inz * * Localfields D i S 10I 0 inz * --------------------------------------------------------- /free
// Search for the file handle i = lf_getFileHandleTableIndex(i_hFile); if (i > 0); if (i_newSize > g_tempBuffer.size); g_tempBuffer.size = g_tempBuffer.size * 2; g_tempBuffer.pData = %realloc(g_tempBuffer.pData : g_tempBuffer.size); endif; endif;
pTmpBuffer = g_tempBuffer.pData;
return pTmpBuffer;
/end-free * P lf_checkAndReallocateTmpBuffer... P E * *========================================================================= R * *** private *** * Returns the file handle table index for a given file handle. *========================================================================= P lf_getFileHandleTableIndex... P B * D lf_getFileHandleTableIndex... D PI 10I 0 D i_hFile const like(ifs_hFile_t) * * Return value D index S 10I 0 inz(-1) * * Localfields D i S 10I 0 inz * --------------------------------------------------------- /free
// Search for the file handle i = %lookup(i_hFile: g_handleList.hFile: 1: g_numHandles); if (i > 0); index = 1; endif;
return index;
/end-free * P lf_getFileHandleTableIndex... P E * *========================================================================= R * *** private *** * Removes the path from the local file handle. *========================================================================= P lp_removeEntryFromFileHandleTable... P B * D lp_removeEntryFromFileHandleTable... D PI D i_hFile const like(ifs_hFile_t) * * Local fields D i S 10I 0 inz * --------------------------------------------------------- /free
i = %lookup(i_hFile: g_handleList.hFile: 1: g_numHandles); if i > 0; g_handleList.hFile(i) = 0; g_handleList.useTmpBuffer(i) = cFalse; g_handleList.path(i) = ''; if i = g_numHandles; g_numHandles = g_numHandles - 1; endif; endif;
// Free temporay buffer used by f_writeLineIfsFile() if (g_numHandles = 0); if (g_tempBuffer.pData <> *NULL); dealloc(N) g_tempBuffer.pData; g_tempBuffer.size = 0; endif; endif;
return;
/end-free * P lp_removeEntryFromFileHandleTable... P E * *========================================================================= R * *** private *** * Converts a timestamp from Epoch to RPG format. *========================================================================= P lf_cvtEpochTmStmpToRpgTmStmp... P B * D lf_cvtEpochTmStmpToRpgTmStmp... D PI Z D i_epochTmStmp 10I 0 value * * Return value D tmStmp S Z inz * * Local fields D ftimef S 16A inz('%Y-%m-%d%H.%M.%S') * D ftimest DS qualified D date 10A D time 8A D null 1A inz(x'00') * D time DS likeds(tm_t) inz * --------------------------------------------------------- /free
if localtime_r(i_epochTmStmp: time) <> *NULL; if strftime(%addr(ftimest) : %size(ftimest) : %trim(ftimef) : time ) > 0; tmStmp=%timestamp(ftimest.date + '-' + ftimest.time + '.000000'); endif; endif;
return tmStmp;
/end-free * P lf_cvtEpochTmStmpToRpgTmStmp... P E * *========================================================================= R * *** private *** * Creates a IFS message. *========================================================================= P lf_newIfsMsg... P B * D lf_newIfsMsg... D PI likeds(msg_t ) D i_ID const like(msg_t.id ) D options(*omit: *nopass) D i_data 512A const varying D options(*omit: *nopass) D i_type const like(msg_t.type ) D options(*omit: *nopass) * * Return value D msg DS likeds(msg_t ) * * Parameter positions D p_ID C const(1) D p_data C const(2) D p_type C const(3) * * Optional parameter fields D ID S like(i_ID ) inz D data S like(i_data ) inz D type S like(i_type ) inz * * Local fields * * Helper fields CEETSTA D isPresent S 10I 0 inz * --------------------------------------------------------- /free
// Process optional parameter values ... // ... ID if %parms >= p_ID; CEETSTA(isPresent: p_ID: *omit); else; isPresent = 0; endif;
if isPresent = 1; ID = i_ID; else; if %parms >= p_ID; ID = cMSG_ID_NONE; else; ID = cMSG_ID_NULL; endif; endif;
// ... Data if %parms >= p_data; CEETSTA(isPresent: p_data: *omit); else; isPresent = 0; endif;
if isPresent = 1; data = i_data; else; data = ''; endif;
// ... Type if %parms >= p_type; CEETSTA(isPresent: p_type: *omit); else; isPresent = 0; endif;
if isPresent = 1; type = i_type; else; if (ID <> cMsg_ID_OK ) and (ID <> cMsg_ID_NULL); type = cMsg_Info; else; type = ''; endif; endif;
msg = f_newMsg(ID: data: type: 'IFS': '*LIBL');
return msg;
/end-free * P lf_newIfsMsg... P E * *========================================================================= R * *** private *** * Checks whether an IFS object is a file; *========================================================================= P lf_isFile... P B * D lf_isFile... D PI N D i_st_stat const likeds(st_stat_t ) * * Return value D isFile S N inz(cFalse) /if not defined(*V5R2M0) * * Local fields D objType S like(st_stat_t.objType) inz /endif * --------------------------------------------------------- /free
/if not defined(*V5R2M0) objType = i_st_stat.objType; if (%str(%addr(objType)) = cIFS_DIRENT_TYPE_FILE ) or (%str(%addr(objType)) = cIFS_DIRENT_TYPE_DOCUMENT); /else if (%str(%addr(i_st_stat.objType)) = cIFS_DIRENT_TYPE_FILE ) or (%str(%addr(i_st_stat.objType)) = cIFS_DIRENT_TYPE_DOCUMENT); /endif isFile = cTrue; else; isFile = cFalse; endif;
return isFile;
/end-free * P lf_isFile... P E * *========================================================================= R * *** private *** * Checks whether an IFS object is a directory; *========================================================================= P lf_isDir... P B * D lf_isDir... D PI N D i_st_stat const likeds(st_stat_t ) * * Return value D isDir S N inz(cFalse) /if not defined(*V5R2M0) * * Local fields D objType S like(st_stat_t.objType) inz /endif * --------------------------------------------------------- /free
/if not defined(*V5R2M0) objType = i_st_stat.objType; if (%str(%addr(objType)) = cIFS_DIRENT_TYPE_DIRECTORY) or (%str(%addr(objType)) = cIFS_DIRENT_TYPE_FOLDER ); /else if (%str(%addr(i_st_stat.objType)) = cIFS_DIRENT_TYPE_DIRECTORY) or (%str(%addr(i_st_stat.objType)) = cIFS_DIRENT_TYPE_FOLDER ); /endif isDir = cTrue; else; isDir = cFalse; endif;
return isDir;
/end-free * P lf_isDir... P E * *========================================================================= R * *** private *** * Checks whether an IFS object matches a given string pattern. *========================================================================= P lf_isEntryEqual... P B * D lf_isEntryEqual... D PI N D i_entry value like(ifs_path_t ) D i_pattern value like(ifs_path_t ) * * Return value D isEqual S N inz(cFalse) * * Local fields D x S 10I 0 inz D wildcard DS qualified D group 1A inz('*') D single 1A inz('?') * --------------------------------------------------------- /free
// Adjust entry, if the user // want to search for name and extension: if %scan('.': i_pattern) > 0;
// Add a dot (.) if it is missing, // to make sure that the dot of the mask // is also in the entry. if %scan('.': %trimR(i_entry)) = 0; i_entry = %trimR(i_entry) + '.'; endif;
endif;
isEqual = f_genStrCmpIgnCase( %trimR(i_entry): %trimR(i_pattern): wildcard);
return isEqual;
/end-free * P lf_isEntryEqual... P E * *========================================================================= R * *** private *** * Initializes the path structure for the Qp0lGetAttr API. *========================================================================= P lf_initializePath... P B * D lf_initializePath... D PI like(ifs_path_t ) D i_path const likeds(Qlg_Path_Name_t) * * Return value D path DS likeds(Qlg_Path_Name_t ) inz * --------------------------------------------------------- /free
clear path; path.CCSID = QLG_PATH_JOB_CCSID; // Use current job default CCSID path.Country_ID = QLG_PATH_JOB_COUNTRYID; // Use the current job country // or region ID path.Language_ID = QLG_PATH_JOB_LANGUAGEID;// Use the current job lang. ID path.Reserved = *ALLx'00'; path.Path_Type = QLG_CHAR_SINGLE; // 0 = Path is character String, // 1-byte delimiter. // 1 = Path is pointer, // 1-byte delimiter. // 2 = Path is character String, // 2-byte delimiter. // 3 = Path is pointer, // 2-byte delimiter. path.Path_Length = %len(%trimR(i_path)); path.Path_Name_Delimiter = cSLASH; path.Reserved2 = *ALLx'00'; path.Path_Name = i_path;
return path;
/end-free * P lf_initializePath... P E * *========================================================================= R * *** private *** * Retrieves a file 'time' attribute. *========================================================================= P lf_getIfsFileTimeAttr... P B * D lf_getIfsFileTimeAttr... D PI 10I 0 D i_path const like(ifs_path_t ) D i_attr 10I 0 const D o_time Z * * Return value D rc S 10I 0 inz * * Helper fields D bytPrv S 10U 0 inz D sizeNeeded S 10U 0 inz D bytRet S 10U 0 inz D path DS likeds(Qlg_Path_Name_t ) inz D attrArray DS likeds(Qlg_attrArray_t ) inz D rtnAttr DS likeds(Qlg_rtnAttr_t ) D based(pRtnAttr) D timeEpo S 10U 0 based(pTimeEpo) * --------------------------------------------------------- /free
// Prepare path name path = lf_initializePath(i_path);
// Specify what attributes we want clear attrArray; attrArray.numE = 1; attrArray.attr(1) = i_attr;
// Allocate buffer for result of Qp0lGetAttr bytPrv = 32; pRtnAttr = %alloc(bytPrv); clear rtnAttr;
// Retrieve file attributes rc = Qp0lGetAttr(path : attrArray : pRtnAttr : bytPrv : sizeNeeded : bytRet : 0 );
if rc = 0; pTimeEpo = pRtnAttr + %size(rtnAttr); o_time = lf_cvtEpochTmStmpToRpgTmStmp(timeEpo); else; o_time = *LOVAL; endif;
return rc;
/end-free * P lf_getIfsFileTimeAttr... P E * /if not defined(*V5R2M0) *===============================================================* * bitand() for V5R1 and below. *===============================================================* P lf_bitand... P B * D lf_bitand... D PI 10U 0 D i_arg1 10U 0 value D i_arg2 10U 0 value * D result S 10U 0 * * AND String (ANDSTR) - MI Instruction * (http://publib.boulder.ibm.com/iseries/v5r1/ic2924/tstudio/tech_ref/mi/topics.htm) D ANDSTR... D PR extproc('_ANDSTR') D i_pReceiver * value D i_pFirstSrc * value D i_pSecondSrc * value D i_length 10U 0 value * - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - /FREE
ANDSTR(%addr(result): %addr(i_arg1): %addr(i_arg2): %len(result));
return result;
/END-FREE * P lf_bitand... P E * /endif

